# Create an FIS experiment template that terminates all instances in us-east-1a
# First, create the IAM role (trust fis.amazonaws.com, policy: EC2 terminate + SSM)

cat > /tmp/fis-experiment.json << 'EOF'
{
  "description": "Simulate us-east-1a outage",
  "targets": {
    "instances-1a": {
      "resourceType": "aws:ec2:instance",
      "resourceTags": {"Env": "staging"},
      "filters": [{"path": "Placement.AvailabilityZone", "values": ["us-east-1a"]}],
      "selectionMode": "ALL"
    }
  },
  "actions": {
    "terminate-1a-instances": {
      "actionId": "aws:ec2:terminate-instances",
      "targets": {"Instances": "instances-1a"}
    }
  },
  "stopConditions": [
    {"source": "aws:cloudwatch:alarm", "value": "arn:aws:cloudwatch:us-east-1:123456789012:alarm:error-rate-critical"}
  ],
  "roleArn": "arn:aws:iam::123456789012:role/FISRole",
  "tags": {"Purpose": "AZ-resilience-test"}
}
EOF

TEMPLATE_ID=$(aws fis create-experiment-template \
  --cli-input-json file:///tmp/fis-experiment.json \
  --query 'experimentTemplate.id' --output text)

echo "Template created: $TEMPLATE_ID"
# Start the experiment (runs in staging only — stop condition halts if error alarm fires)
aws fis start-experiment --experiment-template-id "$TEMPLATE_ID" \
  --query 'experiment.{Id:id,State:state}'
